const userMessage = $('Telegram Trigger').item.json.message.text || '';
const chatId = $('Telegram Trigger').item.json.message.chat.id;

let registry = [];
try {
  const items = $('Read Registry').all();
  if (items && items.length > 0) {
    const first = items[0].json;
    if (Array.isArray(first)) registry = first;
    else if (Array.isArray(first.agents)) registry = first.agents;
    else registry = items.map(i => i.json);
  }
} catch(e) {}

let memory = [];
try {
  const items = $('Read Memory').all();
  if (items && items.length > 0) {
    const first = items[0].json;
    if (Array.isArray(first)) memory = first;
    else if (Array.isArray(first.memory)) memory = first.memory;
    else memory = items.map(i => i.json);
  }
} catch(e) {}

let profile = {};
try {
  const items = $('Read Profile').all();
  if (items && items.length > 0) profile = items[0].json || {};
} catch(e) {}

const userName = String(profile.display_name || '').trim();
const awaitingName = Boolean(profile.awaiting_name);
const profileExists = Boolean(profile.exists);

function cleanTextForPrompt(value) {
  return String(value || '')
    .replace(/[\u4E00-\u9FFF\u3400-\u4DBF\u3000-\u303F\uFF00-\uFFEF\u00C0-\u024F]/g, '')
    .replace(/\[out\]/gi, '').replace(/[\\*`#]/g, '')
    .replace(/(זין|כוס|שרמוט|זונה|מזדיין|בן זונה|fuck|sex|porn)/gi, '')
    .replace(/\s+/g, ' ')
    .trim();
}

const bannedAgentNames = new Set(['agent', 'snakecaseagent', 'snake_case_agent', 'snake_case_name', 'custom_task_agent', 'new_agent', 'helper', 'assistant']);

const activeAgents = registry
  .filter(a => (a.status || 'active') === 'active' && !bannedAgentNames.has(String(a.name || '').toLowerCase()))
  .sort((a, b) => {
    const scoreA = Number(a.score_avg ?? a.score ?? 0);
    const scoreB = Number(b.score_avg ?? b.score ?? 0);
    const usesA = Number(a.uses ?? 0);
    const usesB = Number(b.uses ?? 0);
    return (scoreB - scoreA) || (usesB - usesA);
  });

const agentList = activeAgents.slice(0, 8).length > 0
  ? activeAgents.slice(0, 8).map(a => `- ${a.name}: ${cleanTextForPrompt(a.description)} (מתאים ל: ${cleanTextForPrompt(a.good_for || '')}; ציון: ${a.score_avg ?? a.score ?? 'חדש'}; שימושים: ${a.uses ?? 0})`).join('\n')
  : 'אין עדיין סוכנים';

const recentMemory = memory.slice(-3)
  .map(m => `[${m.agent}] ${cleanTextForPrompt(m.task).substring(0, 120)}`)
  .join('\n') || 'None';

const conversationHistory = memory.slice(-3)
  .map(m => {
    const assistant = m.agent === 'chitchat' ? 'עוזר' : `עוזר [${m.agent}]`;
    return `משתמש: ${cleanTextForPrompt(m.task).substring(0, 180)}\n${assistant}: ${cleanTextForPrompt(m.result).substring(0, 220)}`;
  })
  .join('\n\n') || '';


const skipHistoryTasks = new Set(['הי', 'היי', 'שלום', 'מה נשמע', 'מה קורה']);
const historyTaskWords = ['באיזה סוכן', 'איזה סוכן השתמש', 'איזה נציג השתמש', 'היסטוריית סוכנים', 'שימושי סוכנים', 'זיכרון סוכנים'];
const agentHistoryRows = [...memory].reverse()
  .filter(m => {
    const task = cleanTextForPrompt(m.task || '');
    const isHistoryTask = historyTaskWords.some(word => task.includes(word));
    return task && m.agent && !skipHistoryTasks.has(task) && !isHistoryTask;
  })
  .slice(0, 12)
  .map((m, index) => {
    const task = cleanTextForPrompt(m.task || '').substring(0, 180) || 'לא נשמרה משימה';
    const agent = String(m.agent || 'לא ידוע').trim() || 'לא ידוע';
    const score = (m.score === null || m.score === undefined || m.score === '') ? 'אין' : String(m.score) + '/10';
    const time = String(m.timestamp || '').replace('T', ' ').substring(0, 16) || 'לא נשמר';
    const reason = cleanTextForPrompt(m.decision_reason || m.deductions || '').substring(0, 180) || 'לא נשמרה סיבה';
    return `${index + 1}. משימה:
${task}
סוכן:
${agent}
ציון:
${score}
סיבה:
${reason}
זמן:
${time}`;
  });

const agentHistory = agentHistoryRows.length
  ? `┏━━━━━━━━━━━━━━━━━━
┃ שימושי סוכנים מהזיכרון
┣━━━━━━━━━━━━━━━━━━
┃ משתמש:
┃ ${userName || 'משתמש'}
┃
${agentHistoryRows.join('\n\n')}
┗━━━━━━━━━━━━━━━━━━`
  : `${userName || 'משתמש'}, אין עדיין שימושי סוכנים שמורים בזיכרון האישי שלך.`;

const lastScored = [...memory].reverse().find(m => m.score !== null && m.score !== undefined);
const lastEvaluation = lastScored ? {
  task: lastScored.task || '',
  agent: lastScored.agent || '',
  score: lastScored.score,
  deductions: lastScored.deductions || 'לא נשמר פירוט ניכויים',
  result: cleanTextForPrompt(lastScored.result).substring(0, 500),
  timestamp: lastScored.timestamp || ''
} : null;

return [{ json: { userMessage, chatId, agents: activeAgents, agentList, recentMemory, conversationHistory, lastEvaluation, agentHistory, profile, userName, awaitingName, profileExists } }];

const data = $('Prepare Data').first().json;
const msg = String(data.userMessage || '').trim();
const lower = msg.toLowerCase();
const agents = Array.isArray(data.agents) ? data.agents : [];

const hasAny = (words) => words.some(w => lower.includes(w.toLowerCase()));
const exactCasual = ['הי', 'היי', 'הייי', 'הלו', 'שלום', 'בוקר טוב', 'ערב טוב', 'לילה טוב', 'מה נשמע', 'מה קורה', 'מה המצב', 'תודה', 'סבבה', 'אחלה'];
const detailWords = ['פירוט', 'תן פירוט', 'פרט', 'שלח פירוט', 'פרטים על הציון', 'למה הציון'];
const chitchatWords = ['מי אתה', 'עזרה', 'מה אתה יודע לעשות'];
const codeWords = ['code', 'python', 'javascript', 'js', 'sql', 'html', 'css', 'react', 'bug', 'debug', 'דיבאג', 'קוד', 'פונקציה', 'סקריפט', 'שגיאה'];
const createAgentWords = ['צור לי סוכן', 'תיצור לי סוכן', 'בנה לי סוכן', 'תבנה לי סוכן', 'תכין לי סוכן', 'צור סוכן', 'סוכן חדש', 'נציג חדש'];
const historyWords = ['באיזה סוכן', 'איזה סוכן השתמש', 'איזה נציג השתמש', 'סוכן השתמשת', 'נציג השתמשת', 'היסטוריית סוכנים', 'שימושי סוכנים', 'זיכרון סוכנים', 'סוכן לאיזו משימה', 'נציג לאיזו משימה'];

function cleanName(value) {
  let text = String(value || '').trim();
  const match = text.match(/(?:קוראים לי|השם שלי|אני)\s+([^,.!?\n]+)$/i);
  if (match) text = match[1];
  text = text
    .replace(/^(קוראים לי|השם שלי|אני)\s+/i, '')
    .replace(/(?:^|\s)(תיצור|צור|תעשה|בנה|תבנה|תכין|הכן|צריך|רוצה|סוכן|נציג).*$/i, '')
    .replace(/[^\u0590-\u05FFa-zA-Z\s'-]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  if (text.split(/\s+/).length > 3) return '';
  return text.slice(0, 40);
}

let action = 'create_agent';
let agent_name = null;
let direct_reply = null;
let userName = data.userName || '';
let requestMessage = msg;
let selectionReason = '';

if (!data.userName && !data.awaitingName) {
  action = 'ask_name';
  direct_reply = 'ברוך הבא. איך קוראים לך?\n\nאחרי שתכתוב את השם שלך, אזכור אותו ואפנה אליך בשם בשיחות הבאות.';
} else if ((!data.userName && data.awaitingName) || /^\s*(קוראים לי|השם שלי|אני)\s+/i.test(msg)) {
  const extractedName = cleanName(msg);
  const inlineRequest = (() => {
    const raw = msg.replace(/^\s*(קוראים לי|השם שלי|אני)\s+/i, '').trim();
    const marker = raw.search(/\s(צור|תיצור|תעשה|בנה|תבנה|תכין|הכן|צריך|רוצה)\s/i);
    if (marker > 0) return raw.slice(marker).trim();
    return '';
  })();
  if (extractedName && inlineRequest && inlineRequest.split(/\s+/).filter(Boolean).length >= 3) {
    action = 'create_agent';
    userName = extractedName;
    requestMessage = inlineRequest;
    direct_reply = null;
  } else if (extractedName) {
    action = 'save_name';
    userName = extractedName;
    direct_reply = `נעים מאוד, ${userName}.\n\nמעכשיו אפנה אליך בשם הזה. אם כתבת גם בקשה באותה הודעה, שלח אותה שוב בשורה חדשה ואטפל בה מיד.`;
  } else {
    action = 'ask_name';
    direct_reply = 'לא הצלחתי להבין מה השם בלבד. כתוב רק את השם שלך, למשל: עופר';
  }
} else {
  const wordCount = msg.split(/\s+/).filter(Boolean).length;
  const isShortCasual = wordCount <= 3 && (exactCasual.includes(lower) || hasAny(exactCasual));
  const asksForScoreDetails = hasAny(detailWords);
  const asksForAgentHistory = hasAny(historyWords);

  if (asksForAgentHistory) {
    action = 'chitchat';
    direct_reply = data.agentHistory || `${data.userName || 'משתמש'}, אין עדיין שימושי סוכנים שמורים בזיכרון האישי שלך.`;
  } else if (hasAny(createAgentWords)) {
    action = 'create_agent';
  } else if (asksForScoreDetails) {
    action = 'chitchat';
    const ev = data.lastEvaluation;
    if (ev) {
      direct_reply = `┏━━━━━━━━━━━━━━━━━━
┃ פירוט ציון אחרון
┣━━━━━━━━━━━━━━━━━━
┃ משתמש:
┃ ${data.userName}
┃
┃ סוכן:
┃ ${ev.agent}
┃
┃ ציון:
┃ ${ev.score}/10
┃
┃ סיבה:
┃ ${ev.deductions}
┃
┃ משימה:
┃ ${ev.task}
┗━━━━━━━━━━━━━━━━━━`;
    } else {
      direct_reply = `${data.userName}, אין עדיין ציון שמור בזיכרון האישי שלך.`;
    }
  } else if (!msg || isShortCasual || hasAny(chitchatWords)) {
    action = 'chitchat';
    if (isShortCasual) {
      direct_reply = `${data.userName || 'שלום'}, שלום. איך אפשר לעזור לך עכשיו?`;
    }
  } else if (hasAny(codeWords) && agents.some(a => a.name === 'code_helper')) {
    action = 'use_agent';
    agent_name = 'code_helper';
  } else {
    const tokens = lower
      .replace(/[^a-z0-9א-ת_\s]/gi, ' ')
      .split(/\s+/)
      .filter(t => t.length >= 3);

    const agentTimes = agents
      .map(a => Date.parse(a.updated_at || a.last_used || a.created_at || ''))
      .filter(Number.isFinite);
    const newestTime = agentTimes.length ? Math.max(...agentTimes) : Date.now();
    const oldestTime = agentTimes.length ? Math.min(...agentTimes) : newestTime;
    const timeSpan = Math.max(1, newestTime - oldestTime);

    const candidates = [];
    for (const agent of agents) {
      const haystack = [agent.name, agent.description, agent.good_for].join(' ').toLowerCase();
      let matchScore = 0;
      const matchedTokens = [];
      for (const token of tokens) {
        if (haystack.includes(token)) {
          matchScore += 1;
          matchedTokens.push(token);
        }
      }
      if (matchScore <= 0) continue;

      const agentScore = Number(agent.score_avg ?? agent.score ?? 0) || 0;
      const quality = Math.min(agentScore, 10) / 10;
      const uses = Number(agent.uses ?? 0) || 0;
      const updatedMs = Date.parse(agent.updated_at || agent.last_used || agent.created_at || '') || oldestTime;
      const recency = Math.max(0, Math.min(1, (updatedMs - oldestTime) / timeSpan));
      const freshImprovedBonus = recency >= 0.65 && agentScore >= 8 ? 0.55 : (recency >= 0.65 && agentScore >= 7 ? 0.25 : 0);
      const finalScore = (matchScore * 1.35) + (quality * 0.95) + (recency * 0.55) + (Math.min(uses, 12) / 120) + freshImprovedBonus;

      candidates.push({
        agent,
        matchScore,
        matchedTokens: [...new Set(matchedTokens)].slice(0, 5),
        agentScore,
        uses,
        updatedMs,
        recency,
        finalScore
      });
    }

    candidates.sort((a, b) =>
      (b.finalScore - a.finalScore) ||
      (b.agentScore - a.agentScore) ||
      (b.updatedMs - a.updatedMs)
    );

    let best = candidates[0] || null;
    if (best) {
      for (const candidate of candidates.slice(1)) {
        const closeMatch = candidate.matchScore >= best.matchScore - 0.5;
        const fresherAndNoWorse = candidate.updatedMs > best.updatedMs && candidate.agentScore >= best.agentScore - 0.25;
        const closeEnough = candidate.finalScore >= best.finalScore - 0.35;
        if (closeMatch && fresherAndNoWorse && closeEnough) {
          best = candidate;
        }
      }
    }

    if (best && best.finalScore >= 1.85 && best.matchScore >= 1) {
      action = 'use_agent';
      agent_name = best.agent.name;
      const updated = best.agent.updated_at || best.agent.last_used || best.agent.created_at || 'לא נשמר';
      const freshness = best.recency >= 0.65 ? 'עדכני יחסית' : 'ותיק אבל עדיין מתאים';
      selectionReason = `נבחר ${agent_name} כי הוא מתאים למילים: ${best.matchedTokens.join(', ') || 'התאמה כללית'}. ציון: ${best.agentScore || 'חדש'}, שימושים: ${best.uses}, עדכון אחרון: ${String(updated).replace('T', ' ').substring(0, 16)}. העדפה: ${freshness}; סוכן חדש יותר עם ציון דומה או גבוה מקבל קדימות.`;
    }
  }
}

const decision_reason = action === 'use_agent'
  ? (selectionReason || `נבחר ${agent_name} לפי התאמה, ציון, עדכניות ושימושים קודמים.`)
  : (action === 'create_agent'
    ? 'לא נמצא סוכן מתאים מספיק, לכן נוצר סוכן חדש.'
    : (action === 'ask_name' ? 'משתמש חדש ללא שם שמור.' : (action === 'save_name' ? 'נשמר שם משתמש חדש.' : 'זוהתה שיחה רגילה או בקשת מידע אישי.')));

return [{ json: { action, agent_name, decision_reason, direct_reply, userName, userMessage: requestMessage, chatId: data.chatId } }];

const input = $input.item.json || {};
if (input.action) {
  return [{ json: {
    action: input.action || 'chitchat',
    agent_name: input.agent_name || null,
    decision_reason: input.decision_reason || '',
    direct_reply: input.direct_reply || null,
    userName: input.userName || $('Prepare Data').first().json.userName || '',
    userMessage: input.userMessage || $('Prepare Data').first().json.userMessage,
    chatId: input.chatId || $('Prepare Data').first().json.chatId
  }}];
}

const text = input.response || '';
const cleaned = text.replace(/```json\n?/g, '').replace(/```/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { action: 'chitchat', agent_name: null };
}
const userMessage = $('Prepare Data').first().json.userMessage;
const chatId = $('Prepare Data').first().json.chatId;
return [{ json: {
  action: parsed.action || 'chitchat',
  agent_name: parsed.agent_name || null,
  decision_reason: parsed.decision_reason || '',
  direct_reply: parsed.direct_reply || null,
  userName: $('Prepare Data').first().json.userName || '',
  userMessage,
  chatId
}}];

