const rawTask = String($('Parse Router').first().json.userMessage || '');
const fallbackBase = rawTask
  .toLowerCase()
  .replace(/[^a-z0-9א-ת\s]/gi, ' ')
  .split(/\s+/)
  .filter(Boolean)
  .slice(0, 3)
  .join('_');

function cleanName(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9_]+/g, '_')
    .replace(/^_+|_+$/g, '')
    .replace(/_+/g, '_');
}

function inferAgentName(task) {
  const t = String(task || '').toLowerCase();
  const parts = [];
  if (/מודול|module/.test(t)) parts.push('module');
  if (/נתונ|data|db|database/.test(t)) parts.push('data');
  if (/front|frontend|ui|מסך|ממשק/.test(t)) parts.push('frontend');
  if (/back|backend|שרת/.test(t)) parts.push('backend');
  if (/בדיק|וודא|אימות|validate|test|qa/.test(t)) parts.push('validation');
  if (/ניסוח|כתיב|תוכן|טקסט|copy/.test(t)) parts.push('writing');
  if (/קוד|code|bug|debug|שגיאה/.test(t)) parts.push('code');
  if (/אוטומ|workflow|תהליך/.test(t)) parts.push('automation');
  const unique = [...new Set(parts)].slice(0, 3);
  if (unique.length >= 2) return cleanName(unique.join('_') + '_agent');
  if (unique.length === 1) return cleanName(unique[0] + '_task_agent');
  return 'hebrew_task_agent';
}

let name = cleanName(parsed.name);
const banned = new Set(['snake_case_name', 'snakecaseagent', 'snake_case_agent', 'agent', 'helper', 'assistant', 'new_agent']);
if (!name || banned.has(name) || name.length < 6) {
  name = inferAgentName(rawTask);
}
if (!/[a-z]/.test(name) || banned.has(name) || name.length < 6) {
  name = inferAgentName(rawTask);
}

return [{ json: {
  name,
  description: parsed.description || 'סוכן ייעודי שנוצר לפי הבקשה האחרונה.',
  good_for: parsed.good_for || 'משימות דומות לבקשה האחרונה',
  userMessage: $('Parse Router').first().json.userMessage,
  chatId: $('Parse Router').first().json.chatId
}}];

let response = '';
